{"script":"
const { execSync } = require('child_process');

try {
    // 使用 --prefix 安装到用户目录
    const npmPrefix = execSync('npm config get prefix', { encoding: 'utf-8' }).trim();
    console.log('npm prefix:', npmPrefix);

    // 尝试用 sudo 安装
    console.log('尝试使用 sudo 安装...');
    const result = execSync('sudo npm install -g mcporter@0.8.1 2>&1', {
        encoding: 'utf-8',
        maxBuffer: 10 * 1024 * 1024,
        input: ''  // sudo 可能需要密码，先试试
    });
    console.log(result);
} catch (error) {
    console.error('sudo 安装失败:', error.stderr || error.message);

    // 尝试安装到用户目录
    try {
        console.log('\n尝试安装到用户目录...');
        const homeDir = process.env.HOME;
        const result = execSync(`npm install -g mcporter@0.8.1 --prefix "${homeDir}/.local" 2>&1`, {
            encoding: 'utf-8',
            maxBuffer: 10 * 1024 * 1024
        });
        console.log(result);

        // 检查是否可用
        const mcporterPath = `${homeDir}/.local/bin/mcporter`;
        const fs = require('fs');
        if (fs.existsSync(mcporterPath)) {
            console.log('mcporter 安装成功:', mcporterPath);
        }
    } catch(e) {
        console.error('用户目录安装也失败:', e.stderr || e.message);
    }
}
"}

